SELECT COUNT(DISTINCT component_id) AS total_components
FROM component_equivalents
WHERE manufacturer_id = 0;

SELECT material_name
FROM material_types
WHERE material_id = 1;

SELECT AVG(weight) AS average_weight
FROM components
WHERE material_type = 'Stainless Steel' AND corrosion_resistance = 1;

SELECT document_type, document_description
FROM component_documents
WHERE component_id = 1 AND upload_date = '2023-05-01 10:00:00';

SELECT tag_name
FROM component_tags
WHERE component_id = 0;

SELECT attribute_name, attribute_value
FROM component_attributes
WHERE component_id = 1;
